#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char name[105];
        int score, age;
        // Read name (may contain spaces) up to newline
        scanf(" %104[^\n]", name);
        scanf("%d %d", &score, &age);
        if (score > 10 && age > 20) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

