#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin>>T)) return 0;
    string dummy;
    getline(cin, dummy); // consume end‑of‑line after T
    while (T--) {
        string name;
        getline(cin, name); // read full name line
        int score, age;
        cin >> score >> age;
        getline(cin, dummy); // consume end‑of‑line after age
        if (score > 10 && age > 20) cout << "YES\n";
        else cout << "NO\n";
    }
    return 0;
}

